object Solution { def versioned_kv(operations: Seq[Seq[Any]]): Seq[Any] = { val history = scala.collection.mutable.Map[String, scala.collection.mutable.ArrayBuffer[Int]](); val table = scala.collection.mutable.Map[(String, Int), Any](); val out = scala.collection.mutable.ArrayBuffer[Any](); for (op <- operations) { if (op(0) == "SET") { val key = op(1).toString; val ts = asInt(op(3)); val stamps = history.getOrElseUpdate(key, scala.collection.mutable.ArrayBuffer[Int]()); val pos = lowerBound(stamps, ts); if (pos == stamps.length || stamps(pos) != ts) stamps.insert(pos, ts); table((key, ts)) = op(2) } else { val key = op(1).toString; val ts = asInt(op(2)); val stamps = history.getOrElse(key, scala.collection.mutable.ArrayBuffer[Int]()); val pos = upperBound(stamps, ts); out += (if (pos == 0) null else table((key, stamps(pos - 1)))) } }; out.toSeq }; private def lowerBound(values: scala.collection.mutable.ArrayBuffer[Int], target: Int): Int = { var lo = 0; var hi = values.length; while (lo < hi) { val mid = (lo + hi) / 2; if (values(mid) < target) lo = mid + 1 else hi = mid }; lo }; private def upperBound(values: scala.collection.mutable.ArrayBuffer[Int], target: Int): Int = { var lo = 0; var hi = values.length; while (lo < hi) { val mid = (lo + hi) / 2; if (values(mid) <= target) lo = mid + 1 else hi = mid }; lo }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
